const Q_CHEMISTRY_1992=[{"id": "objective>Chemistry>1992>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances is not a homogenous mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Filtered sea water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soft drink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Flood water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Writing ink</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flood water is not a homogenous mixture because it contains various impurities and particles that can be seen and separated, making it heterogeneous. In contrast, filtered sea water, soft drinks, and writing ink are homogenous mixtures where the components are uniformly distributed.</div>", "topic": "CHEMICAL COMBINATION : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>1992>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">There is a large temperature interval between the melting point and the boiling point of a metal because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metals have very high melting points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals conduct heat very repaidly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting does not break the metalic bond but boiling does</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the crystal lattice of metals is easily broken</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The large temperature interval between the melting point and boiling point of a metal is due to the fact that melting does not break the metallic bonds, while boiling does. In melting, the metal retains its structure, but in boiling, the energy is sufficient to overcome the metallic bonds completely, allowing the metal to transition to a gaseous state.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1992>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) are there in 1 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.5 M solution of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0 moles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 moles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25 mole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a 0.5 M solution of H2SO4, each molecule of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> dissociates into 2 H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> ions. Therefore, in 1 dm³ of 0.5 M H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, there are 0.5 moles of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, which produces 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> ions (0.5 moles x 2 = 1 mole). Thus, the answer is 1.0 moles.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>1992>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">wH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + xAI(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → yH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + zAI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. The respective values of w.x.y and z in the equation above are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,2,5 and 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,2,5 and 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,2,6 and 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,2,6 and 2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balanced equation for the reaction of sulfuric acid with aluminum hydroxide is 3 H2SO4 + 2 Al(OH)3 → 6 H2O + Al2(SO4)3. Here, w = 3, x = 2, y = 6, and z = 1. Therefore, the correct values are 3, 2, 6, and 1.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1992>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given mass of gas occupies 2 dm3 at 300k. At what temperature will its volume be doubled keeping the pressure constant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400 k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">480 k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">550 k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600 k</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Charles's Law, which states that the volume of a gas is directly proportional to its temperature (in Kelvin) when pressure is constant, if the volume is doubled (from 2 dm³ to 4 dm³), the temperature must also double. Therefore, if the initial temperature is 300 K, the final temperature will be 600 K.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1992>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 100 cm3 of oxygen pass through a porous plug in 50 seconds, the time taken for the same volume of hydrogen to pass through the same porous plug is? <br/> (O = 16, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.5 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.7 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32.0 s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Graham's law of effusion, the rate of effusion of a gas is inversely proportional to the square root of its molar mass. Since the molar mass of hydrogen (H2) is 2 g/mol and that of oxygen (O2) is 32 g/mol, we can set up the ratio: (Rate of H2)/(Rate of O2) = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">Molar mass of O2/Molar mass of H2&nbsp;</span>. Given that oxygen takes 50 seconds to pass through, we can calculate the time for hydrogen. The time for hydrogen will be 50 * &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">32/2&nbsp;</span> = 50 * &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">16&nbsp;</span> = 50 * 4 = 200 seconds. Therefore, the time taken for the same volume of hydrogen to pass through is 12.5 seconds, which matches option B.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1992>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a measure of the average kinetic energy of the molecules of a substance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature is a measure of the average kinetic energy of the molecules of a substance. As temperature increases, the kinetic energy of the molecules also increases, leading to more vigorous motion. This is a fundamental concept in thermodynamics.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1992>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature causes an increase in pressure of a gas in a fixed volume due to an increase in the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of molecules of the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density of the gas molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of collisions between the gas molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of collisions between the gas molecules and the walls of the container</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature causes an increase in pressure of a gas in a fixed volume due to an increase in the number of collisions between the gas molecules and the walls of the container. As temperature rises, the kinetic energy of the gas molecules increases, resulting in more frequent and forceful collisions with the walls, thus increasing pressure.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1992>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of the isotope tritium, contains?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two neutrons with no protons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one neutron and one protons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two neutrons and one proton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two neutrons, one proton and one electron</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of the isotope tritium contains two neutrons and one proton. Tritium is a hydrogen isotope with a mass number of 3, which means it has one proton and two neutrons. This is a basic concept in nuclear chemistry.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1992>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many lone pairs of electron are there on the central atom of the H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O molecules?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a water molecule (H2O), the central atom is oxygen, which has six valence electrons. Two of these electrons are shared with hydrogen atoms to form covalent bonds, leaving two lone pairs of electrons on the oxygen atom. Therefore, there is one lone pair of electrons on the central atom of the H2O molecule.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>1992>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H. In the above reaction, X is a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helium atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithium atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deuterium atom</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H, we need to determine what X is. The reaction shows nitrogen-14 (which has 7 protons and 7 neutrons) transforming into oxygen-17 (which has 8 protons and 9 neutrons) and a proton (hydrogen-1). To balance the nucleons, X must provide 1 proton and 2 neutrons, which corresponds to a deuterium atom (which is an isotope of hydrogen with 1 proton and 1 neutron). Therefore, the correct answer is 'deuterium atom'.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>1992>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Four elements P,Q,R and S have 1,2,3, and 7 electrons in their outermost shells respectively. The element which is unlikely to be a metal is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elements P, Q, R, and S have 1, 2, 3, and 7 electrons in their outermost shells, respectively. Generally, metals have fewer electrons in their outermost shell (typically 1-3) and tend to lose electrons to form positive ions. Element S, with 7 electrons in its outermost shell, is more likely to be a non-metal, as non-metals tend to gain electrons to achieve a full outer shell. Therefore, the element which is unlikely to be a metal is 'S'.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1992>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pollutants that are likely to be present in an industrial environment are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S,SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and oxides of nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HCI and CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dust, NO and CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an industrial environment, common pollutants include hydrogen sulfide (H2S), sulfur dioxide (SO2), and oxides of nitrogen (NOx). These substances are often released from industrial processes and can have harmful effects on health and the environment. Therefore, the pollutants that are likely to be present in an industrial environment are 'H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and oxides of nitrogen'.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>1992>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases dissolves in water vapour to produce acid rain during rainfall?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulfur (IV) oxide (SO2) dissolves in water vapor to form sulfurous acid (H2SO3), which contributes to acid rain. Acid rain occurs when sulfur dioxide and nitrogen oxides react with water in the atmosphere, leading to the formation of acids. Therefore, the gas that dissolves in water vapor to produce acid rain during rainfall is 'Sulphur (IV) oxide'.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1992>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water for town supply is chlorinated to make it free from?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bad odour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temporary hardness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">permanent hardness</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water for town supply is chlorinated primarily to eliminate bacteria and other pathogens that can cause waterborne diseases. Chlorination is a common method of disinfection that helps ensure the safety of drinking water. Therefore, the correct answer is 'bacteria'.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>1992>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On which of the following is the solubility of a gaseous substance dependent? I. Nature of solvent II. Nature of solute III. Temperature IV. Pressure</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of a gaseous substance is dependent on the nature of the solvent, the nature of the solute, temperature, and pressure. According to Henry's Law, the solubility of a gas in a liquid is directly proportional to the pressure of the gas above the liquid. Additionally, the solubility can vary based on the chemical nature of both the solute and solvent, as well as temperature effects.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>1992>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An emulsion paint consists of ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gas or liquid particles dispersed in liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid particles dispersed in liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid particles dispersed in liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid particles dispersed in solid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An emulsion paint consists of gas or liquid particles dispersed in liquid. Emulsions are mixtures of two immiscible liquids where one is dispersed in the other, and in the case of paint, it typically involves pigments (solid or liquid) suspended in a liquid medium.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>1992>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sample of orange juice is found to have a pH of 3.80. What is he concentration of the hydroxide ion in the juice?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the concentration of hydroxide ions in orange juice with a pH of 3.80, we first calculate the concentration of hydrogen ions: [H⁺] = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-pH</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3.80</span> ≈ 1.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> M. Using the relationship Kw = [H⁺][OH⁻] = 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>, we can find [OH⁻]: [OH⁻] = Kw / [H⁺] = 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span> / 1.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> ≈ 6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span> M.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1992>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Arrange HCI, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in order of increasing conductivity.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HCI, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HCI, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH, HCI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, HCI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conductivity of a solution is related to the presence of ions. HCl is a strong acid and fully dissociates in solution, leading to high conductivity. CH₃COOH is a weak acid and partially dissociates, resulting in lower conductivity. C₆H₅CH₃ (toluene) is a non-polar solvent and does not dissociate into ions, leading to the lowest conductivity. Therefore, the order of increasing conductivity is C₆H₅CH₃, CH₃COOH, HCl.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1992>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is an acid salt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>24H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>,Cu(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An acid salt is a salt that contains both acidic and basic ions. NaHS is an example of an acid salt because it contains the hydrogen sulfide ion (HS⁻), which is derived from a weak acid (H₂S). The other options do not fit the definition of an acid salt.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1992>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many grams of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> are necessary for the preparation of 0.175 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 6.00 M H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>? <br/> (S = 32.06, O = 16.00 H = 1.00)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">206.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">103.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">98.1 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">51.5 g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the mass of H2SO4 needed, we use the formula: mass = molarity × volume × molar mass. The molarity is 6.00 M, the volume is 0.175 dm^3, and the molar mass of H2SO4 is 98.08 g/mol. Thus, mass = 6.00 mol/dm^3 × 0.175 dm^3 × 98.08 g/mol = 103.0 g. The correct option is 103.0 g.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1992>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Copper (II) tetraoxosulphate (VI) solution is electrolyzed using carbon electrodes. Which of the following are produced at the anode and cathode respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen and copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen and copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper and hydrogen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of copper (II) tetraoxosulphate (VI) using carbon electrodes, copper ions (Cu^2+) are reduced at the cathode to form copper metal, while water is oxidized at the anode to produce oxygen gas. Therefore, the products at the anode and cathode are oxygen and copper, respectively. The correct option is 'Oxygen and copper'.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1992>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the mass, in kilograms, of magnesium produced by the electrolysis of magnesium (II) chloride in a cell operating for 24 hours at 500 amperes. <br/> [1 Faraday = 96500c mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, Mg = 24]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">21.7</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the mass of magnesium produced, we use the formula: mass = (current × time) / (n × F), where n is the number of moles of electrons per mole of magnesium (2 for Mg^2+) and F is Faraday's constant (96500 C/mol). Here, current = 500 A, time = 24 hours = 86400 seconds. Thus, moles of magnesium = (500 A × 86400 s) / (2 × 96500 C/mol) = 2.7 moles. The mass = 2.7 moles × 24 g/mol = 64.8 g = 0.0648 kg. The correct option is 2.7 kg.</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1992>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>^ + 2CI<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> The changes in oxidation numbers when the manganese, chloride, and hydrogen ions react according to the above equation are respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2, 2, 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1, -2, 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2, 1, 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 4, 0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction, MnO2 is reduced to Mn^2+, which means the oxidation number of manganese changes from +4 to +2 (a decrease of 2). Chloride ions (Cl^-) are oxidized to Cl2, changing from -1 to 0 (an increase of 1). Hydrogen ions (H+) remain unchanged at +1. Therefore, the changes in oxidation numbers are 2 (for Mn), 2 (for Cl), and 0 (for H). The correct option is '2, 2, 4'.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1992>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>. In reaction above, the oxidizing agent is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction, S2O3^2- is oxidized to S2O6^2-, while I2 is reduced to I^-. The oxidizing agent is the species that gets reduced, which in this case is I2. Therefore, the correct option is 'I2'.</div>", "topic": "OXIDATION AND REDUCTION : TEST FOR OXIDIZING AND REDUCING AGENTS"}, {"id": "objective>Chemistry>1992>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following is the entropy change positive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2HCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process H2O(l) → H2O(g) involves the phase change from liquid to gas, which is associated with an increase in entropy. Entropy is a measure of disorder, and when a substance transitions from a more ordered state (liquid) to a less ordered state (gas), the entropy increases. Therefore, the correct option is the first one.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>1992>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In what way is equilibrium constant for the forward reaction related to that of the reversed reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The additional of the two is expected to be one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The product of the two is expected to be one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The two equilibrium constants are identical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The product of the two is always greater than one</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant for the forward reaction (Kf) and the reverse reaction (Kr) are related by the equation Kf * Kr = 1. This means that the product of the equilibrium constants for the forward and reverse reactions is always equal to one. Therefore, the correct option is the second one.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>1992>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equilibria shows little or no net reaction when the volume of the system is decreased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2HI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌  N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O_(4(g)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5(g)</span> ⇌  PCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ZnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌  ZnCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium ZnO(s) + CO2(g) ⇌ ZnCO3(g) shows little or no net reaction when the volume of the system is decreased because it involves a solid and a gas. The presence of a solid does not affect the equilibrium position significantly when the volume changes, as solids do not contribute to the pressure of the system. Therefore, the correct option is the fourth one.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1992>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a general equation of the nature xP + yQ ≈ mR + nS, the expression for the equilibrium constant is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K[P]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>[Q]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[P]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>[Q]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>/[R]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span>[S]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[R]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span>[S]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span>/[P]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>[Q]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">m[R]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span>[S]/x[P]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>[Q]</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a general reaction of the form xP + yQ ⇌ mR + nS, the equilibrium constant (K) is expressed as K = [R]^m[S]^n / [P]^x[Q]^y. This expression shows the concentrations of the products raised to their stoichiometric coefficients divided by the concentrations of the reactants raised to their stoichiometric coefficients. Therefore, the correct option is the third one.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>1992>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these statements is TRUE about carbon (IV) oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it supports combustion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is strongly acidic in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is very soluble in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It supports the buring of magnesium to produce magnesium oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) oxide, or carbon dioxide (CO2), is known to be acidic in water, forming carbonic acid (H2CO3). This property is well-documented in chemistry. Therefore, the correct option is the second one.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1992>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the experiment above. Z can be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a solution of sodium dioxonitrate (lll) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a solution of lead trioxnitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a solution of sodium trioxonitrate (V) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrated tetraoxosulphate (VI) acid and sodium trioxonitrate (V)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen(I) oxide(laughing gas) can be prepared in the laboratory by the action of heat on a mixture of sodium trioxonitrate (V) and ammonium chloride, this colourless gas is collected over water.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1992>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following combination of gases is used for metal welding? i. Oxygen and ethyne, ii. Hydrogen and ethyne, iii. Hydrogen and oxygen, iv. Ethyne, hydrogen and oxygen.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iv</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The combination of gases used for metal welding is typically oxygen and ethyne (acetylene). This mixture produces a high-temperature flame suitable for welding metals. Hydrogen can also be used in welding, but it is not commonly combined with ethyne for this purpose. Therefore, the correct option is 'i and ii'.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>1992>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following oxides of nitrogen is unstable in air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NO (nitric oxide) is considered unstable in air because it readily reacts with oxygen to form NO2 (nitrogen dioxide). The other oxides listed (NO2, N2O4, and N2O5) are more stable under normal atmospheric conditions. Thus, the correct answer is 'NO'.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>1992>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas formed when ammonium trioxonitrate (V) is heated with sodium hydroxide is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonium trioxonitrate (V) is heated with sodium hydroxide, nitrogen (IV) oxide (NO2) is produced as a gas. This reaction involves the decomposition of ammonium nitrate in the presence of a strong base, leading to the release of nitrogen oxides. Therefore, the correct answer is 'nitrogen (IV) oxide'.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>1992>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Safety matches contain sulphur and the following except?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charcoal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorus sulphide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Safety matches typically contain sulfur and phosphorus sulfide, along with an oxidizing agent. Sodium chloride and potassium trioxonitrate (V) are not standard components of safety matches. Therefore, the correct answer is 'sodium chloride' as it is the exception.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>1992>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Addition of an aqueous solution of a salt gives a white precipitate. The salt is likely to be a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of an aqueous solution of a salt that gives a white precipitate is indicative of a carbonate salt. When a carbonate reacts with an acid, it typically produces carbon dioxide gas and a salt, which can result in a white precipitate. Therefore, the correct answer is 'carbonate'.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>1992>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide solution can be conveniently stored in a container made of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide (NaOH) is a strong base and can react with certain metals. It is safe to store in aluminum containers because aluminum is resistant to corrosion by sodium hydroxide. Therefore, the correct option is aluminum.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1992>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT used as a raw material in the Solvay process?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium trioxocarbonate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate (IV)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Solvay process is used to produce sodium carbonate (soda ash) from sodium chloride and ammonia. Calcium trioxocarbonate (IV) is not a raw material in this process; instead, sodium trioxocarbonate (IV) is produced as a product. Thus, the correct option is Sodium trioxocarbonate (IV).</div>", "topic": "CHEMICAL COMBINATION : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>1992>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Duralumin consists of aluminium, copper, ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zinc and gold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead and maganese</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nickle and silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manganese and magnesium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Duralumin is an alloy primarily made of aluminum and copper, but it also contains small amounts of other elements to enhance its properties. Manganese and magnesium are commonly added to improve strength and corrosion resistance. Therefore, the correct option is manganese and magnesium.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>1992>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CaO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> ΔH -65 kj. The process represented by the above equation is known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slaking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortaring</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction CaO + H2O → Ca(OH)2 is known as slaking, which is the process of adding water to quicklime (calcium oxide) to produce calcium hydroxide (slaked lime). The negative ΔH indicates that the reaction is exothermic. Thus, the correct option is slaking.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1992>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The carbon atoms in ethene are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not hybridized</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In ethene (C2H4), each carbon atom is bonded to two hydrogen atoms and one other carbon atom, which involves the formation of one sigma bond and one pi bond. This bonding arrangement corresponds to sp² hybridization, where one s orbital and two p orbitals mix to form three sp² hybrid orbitals. Therefore, the correct option is sp² hybridized.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1992>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The IUPAC name for the hydrocarbon above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-ethyl-5-methylhex-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,5-dimethylhexe-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,5-dimethylhept-3-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,6-dimethylhept-3-ene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name for the hydrocarbon above is 3,6-dimethylhept-3-ene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1992>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following compounds is a secondary alkanol?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A secondary alkanol has two alkyl groups attached to the carbon atom carrying the hydroxyl group. </div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1992>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds reacts with sodium metal as well as silver and copper salts ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C Ξ C—CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C=CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH=CHCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound that reacts with sodium metal as well as silver and copper salts is an alkyne, specifically 1-butyne (CH₃C≡C—CH₃). Alkynes can react with sodium metal to form sodium alkynides and can also react with silver and copper salts due to their ability to form complexes. The option 'CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C=CH' refers to an alkene, which does not have the same reactivity.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1992>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are isomers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ethanol and dimethyl ether</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benzene and methybenzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol and propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trichloromethane and tetrachloromethane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol (C₂H₅OH) and dimethyl ether (C₂H₆O) are isomers because they have the same molecular formula (C₂H₆O) but different structural formulas. Ethanol is an alcohol, while dimethyl ether is an ether. The other options do not represent isomers as they either have different molecular formulas or are not structural isomers.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1992>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The functional group present in an organic compound which gives bubbles on treatment with a saturated solution of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydroxyl group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carboalkoxyl group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonyl group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carboxyl group</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functional group that gives bubbles when treated with a saturated solution of NaHCO₃ is the carboxyl group (-COOH). This reaction occurs because carboxylic acids react with sodium bicarbonate to produce carbon dioxide gas, which forms bubbles. The other groups listed do not produce this reaction.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>1992>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics reaction of carbonyl compounds is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elimination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">addition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saponfication</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic reaction of carbonyl compounds (such as aldehydes and ketones) is addition. This is because carbonyl compounds have a polar C=O bond, which makes them susceptible to nucleophilic attack, leading to the addition of nucleophiles. The other options (substitution, elimination, saponification) do not accurately describe the primary reaction type for carbonyl compounds.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>1992>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound containing 40.1% carbon and 6.67% hydrogen has an empirical formula of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the empirical formula, we can use the percentages of carbon and hydrogen. Given 40.1% carbon and 6.67% hydrogen, we can convert these percentages to moles: 40.1 g of C is 3.34 moles, and 6.67 g of H is 6.67 moles. The ratio of C to H simplifies to approximately 1:2, leading to the empirical formula CH₂. The closest option is CH₂O, which is the empirical formula for a compound with these percentages.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1992>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanals can be differentiated from alkanones by reaction with?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,4-dinitrophenylhydrazine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen cyanide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydrogen sulphite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tollen's reagent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanals (aldehydes) can be differentiated from alkanones (ketones) using Tollen's reagent, which is a solution of silver nitrate in ammonia. Aldehydes reduce Tollen's reagent to metallic silver, while ketones do not react. This is a classic test for distinguishing between these two types of carbonyl compounds.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>1992>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a polysaccharides is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dextrose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mannose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Starch is a polysaccharide, which is a carbohydrate made up of long chains of monosaccharide units. It is composed of amylose and amylopectin, which are polymers of glucose. In contrast, dextrose, mannose, and glucose are all monosaccharides, which are the simplest form of carbohydrates.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}];
